export const getTasks: GetTasks<void, any[]> = async (args, context) => {
  return context.entities.Task.findMany({
    orderBy: { position: 'asc' },
  })
}

import { type CreateTask, type MoveTaskUp } from 'wasp/server/actions'
import { HttpError } from 'wasp/server'

export const createTask: CreateTask<{ description: string }, any> = async ({ description }, context) => {
  const lastTask = await context.entities.Task.findFirst({
    orderBy: { position: 'desc' },
  })
  const nextPosition = lastTask ? lastTask.position + 1 : 0
  return context.entities.Task.create({
    data: {
      description,
      position: nextPosition,
    },
  })
}

export const moveTaskUp: MoveTaskUp<{ id: number }, any> = async ({ id }, context) => {
  const task = await context.entities.Task.findUnique({
    where: { id },
  })
  if (!task) throw new HttpError(404, 'Task not found')
  if (task.position === 0) return task

  const previousTask = await context.entities.Task.findFirst({
    where: { position: task.position - 1 },
  })
  if (!previousTask) throw new HttpError(404, 'Previous task not found')

  return await context.entities.$transaction([
    context.entities.Task.update({
      where: { id: task.id },
      data: { position: previousTask.position },
    }),
    context.entities.Task.update({
      where: { id: previousTask.id },
      data: { position: task.position },
    }),
  ])
}

